// The problem generics solve
// Version A: one function per type — duplication
function firstString(arr: string[]): string { return arr[0]; }
function firstNumber(arr: number[]): number { return arr[0]; }

// Version B: use any — loses all type information
function firstAny(arr: any[]): any { return arr[0]; }

// Version C: generics — one function, full type safety
function first<T>(arr: T[]): T { return arr[0]; }

const s = first(['hello', 'world']); // s: string — inferred from the array
const n = first([1, 2, 3]);          // n: number
const b = first([true, false]);      // b: boolean

// Generic function
function identity<T>(value: T): T { return value; }

// Generic arrow function (comma needed in .tsx to avoid JSX ambiguity)
const wrap = <T,>(value: T): { value: T } => ({ value });

// Generic interface
interface Container<T> {
  value: T;
  map<U>(fn: (v: T) => U): Container<U>;
}

// Generic class
class Box<T> {
  constructor(private item: T) {}
  get(): T { return this.item; }
}

// Generic type alias
type Nullable<T> = T | null;
type Pair<A, B> = [A, B];

// Usage
const a = identity(42);          // T = number; a: number
const b = new Box('hello');      // T = string; Box<string>
const c: Nullable<string> = null; // string | null

function echo<T>(x: T): T { return x; }

// Inferred — TypeScript knows x is string from the literal
const s = echo('hello'); // T = string

// Explicit — caller forces T = string even if the argument would infer wider
const t = echo<string>('hello'); // T = string — same result here

// Inference from arrays
function head<T>(arr: T[]): T { return arr[0]; }
const n = head([1, 2, 3]); // T = number

// Inference from callback return
function transform<T, U>(arr: T[], fn: (item: T) => U): U[] {
  return arr.map(fn);
}
const lengths = transform(['a', 'bb', 'ccc'], s => s.length);
// T = string, U = number; lengths: number[]

// When inference fails — TypeScript cannot infer T from an empty call
function create<T>(): T[] { return []; }
// const list = create();        // Error: cannot infer T
const list = create<string>(); // OK — explicit type argument required

// A and B can be different types
function zip<A, B>(as: A[], bs: B[]): [A, B][] {
  return as.map((a, i) => [a, bs[i]]);
}

const pairs = zip([1, 2, 3], ['a', 'b', 'c']);
// pairs: [number, string][]

// Mapping one type to another
function mapRecord<K extends string, V, W>(
  rec: Record<K, V>,
  fn: (v: V) => W,
): Record<K, W> {
  return Object.fromEntries(
    (Object.entries(rec) as [K, V][]).map(([k, v]) => [k, fn(v)])
  ) as Record<K, W>;
}

const prices = { apple: 1.5, banana: 0.75, cherry: 3.0 };
const formatted = mapRecord(prices, p => `$${p.toFixed(2)}`);
// formatted: Record<string, string>

// Without constraint — no member access allowed
function bad<T>(arr: T[]): number {
  // return arr[0].length; // Error: T has no 'length' property
}

// With constraint — length is guaranteed
function longest<T extends { length: number }>(a: T, b: T): T {
  return a.length >= b.length ? a : b;
}

longest('hello', 'world');  // T = string
longest([1, 2], [3]);       // T = number[]
// longest(1, 2);            // Error: number has no 'length'

// keyof constraint — type-safe property access
function pluck<T, K extends keyof T>(items: T[], key: K): T[K][] {
  return items.map(item => item[key]);
}

const users = [{ id: 1, name: 'Alice' }, { id: 2, name: 'Bob' }];
const names = pluck(users, 'name'); // string[]
const ids   = pluck(users, 'id');   // number[]
// pluck(users, 'age');              // Error: 'age' is not a key of User

// Partial<T> — all properties become optional
type Partial<T> = { [K in keyof T]?: T[K] };

// Readonly<T> — all properties become readonly
type Readonly<T> = { readonly [K in keyof T]: T[K] };

// Record<K, V> — object with keys K and values V
type Record<K extends string | number | symbol, V> = { [P in K]: V };

// Pick<T, K> — keep only listed properties
type Pick<T, K extends keyof T> = { [P in K]: T[P] };

// Exclude<T, U> — remove union members assignable to U
type Exclude<T, U> = T extends U ? never : T;

// ReturnType<F> — extract the return type of a function type
type ReturnType<T extends (...args: any) => any> = T extends (...args: any) => infer R ? R : any;

// Example: compose utility types
interface User { id: number; name: string; email: string; role: string }

type UpdatePayload  = Partial<Pick<User, 'name' | 'email'>>;
// { name?: string; email?: string }

type AdminUser = Readonly<User & { permissions: string[] }>;
// All properties readonly, plus permissions

import { HttpClient } from '@angular/common/http';
import { Injectable } from '@angular/core';
import { Observable } from 'rxjs';
import { Signal, signal, computed } from '@angular/core';

// Angular's HttpClient.get<T>() is a generic method
// T tells the caller what shape the JSON response will have
@Injectable({ providedIn: 'root' })
class DataService {
  constructor(private http: HttpClient) {}

  fetch<T>(url: string): Observable<T> {
    return this.http.get<T>(url);
  }
}

// Angular Signals are generic
const count = signal<number>(0);          // WritableSignal<number>
const name  = signal<string | null>(null); // WritableSignal<string | null>
const doubled = computed(() => count() * 2); // Signal<number>

// EventEmitter is generic
import { EventEmitter } from '@angular/core';
const valueChange = new EventEmitter<string>();
valueChange.emit('new value');  // only strings allowed
// valueChange.emit(42);        // Error: number is not string

// InjectionToken is generic
import { InjectionToken } from '@angular/core';
const API_URL = new InjectionToken<string>('ApiUrl');
// The type parameter documents what DI will return

// Simple default — T defaults to string
function makeList<T = string>(item: T): T[] { return [item]; }

makeList('hello');    // T = string (inferred) — same result as the default
makeList(42);         // T = number (inferred)
makeList<boolean>(true); // T = boolean (explicit)
// makeList()           // T = string (default — cannot infer from no argument)

// Default on an interface
interface ApiResponse<T = unknown> {
  data: T;
  status: number;
}

const raw: ApiResponse = { data: {}, status: 200 };       // T = unknown
const typed: ApiResponse<User[]> = { data: [], status: 200 }; // T = User[]

interface User { id: number; name: string }

// Default that references an earlier parameter
type Callback<T, R = T> = (value: T) => R;

const identity: Callback<number> = n => n;       // T = number, R = number
const toString: Callback<number, string> = n => String(n); // T = number, R = string

// Covariant position — return type
type Producer<T> = () => T;

// If Dog extends Animal, then Producer<Dog> extends Producer<Animal>
interface Animal { name: string }
interface Dog extends Animal { breed: string }

const dogProducer: Producer<Dog> = () => ({ name: 'Rex', breed: 'Labrador' });
const animalProducer: Producer<Animal> = dogProducer; // OK — covariant

// Contravariant position — function parameter type
type Consumer<T> = (value: T) => void;

// If Dog extends Animal, then Consumer<Animal> extends Consumer<Dog>
const animalConsumer: Consumer<Animal> = (a) => console.log(a.name);
const dogConsumer: Consumer<Dog> = animalConsumer; // OK — contravariant

// Invariant — read/write position (mutable container)
interface Mutable<T> { value: T }
// Mutable<Dog> is NOT assignable to Mutable<Animal> because:
// - You could write animalBox.value = new Cat() through an Animal reference
// - but it's actually a Dog container — type unsound

// TypeScript is structurally typed — it permits these through object widening,
// but understanding variance explains why some generics should be readonly:
interface Readonly_<T> { readonly value: T }
const dogBox:    Readonly_<Dog>    = { value: { name: 'Rex', breed: 'Lab' } };
const animalBox: Readonly_<Animal> = dogBox; // OK — readonly is covariant

// Narrowing with in operator
function process<T extends { kind: 'text'; value: string } | { kind: 'number'; value: number }>(
  item: T,
): string {
  if (item.kind === 'text') {
    return item.value.toUpperCase(); // item.value: string — narrowed
  }
  return item.value.toFixed(2);     // item.value: number — narrowed
}

// typeof narrowing on a constrained generic
function stringify<T extends string | number | boolean>(value: T): string {
  if (typeof value === 'string') return value;       // value: string
  if (typeof value === 'number') return value.toFixed(2); // value: number
  return String(value);                              // value: boolean
}

// instanceof narrowing — works when the constraint includes a class type
function getLength<T extends string | ArrayLike<unknown>>(value: T): number {
  return value.length;
}

// discriminated union narrowing
interface Success<T> { ok: true;  data: T }
interface Failure    { ok: false; error: string }
type Result<T> = Success<T> | Failure;

function unwrap<T>(result: Result<T>): T {
  if (result.ok) return result.data; // result: Success<T>
  throw new Error(result.error);     // result: Failure
}

// Widening — inferred as string, not a literal
function asLiteral<T>(value: T): T { return value; }

const a = asLiteral('hello');     // T = string — widened, not 'hello'
const b = asLiteral('hello' as const); // T = 'hello' — narrow literal preserved

// Array widening
function firstTwo<T>(arr: T[]): [T, T] {
  return [arr[0], arr[1]];
}

const pair = firstTwo([1, 2, 3]);  // T = number — fine
const mixed = firstTwo([1, 'a']);  // T = string | number — widened union

// Fix: provide an explicit type argument to pin the literal
const literal = firstTwo<'a' | 'b'>(['a', 'b']); // OK

// Common in Angular — HttpParams, InjectionToken
import { InjectionToken } from '@angular/core';
const TOKEN1 = new InjectionToken('MyToken');       // InjectionToken<unknown>
const TOKEN2 = new InjectionToken<string>('MyToken'); // InjectionToken<string> — explicit

// 1. Identity — return the value unchanged, preserving its type
const identity = <T,>(x: T): T => x;

// 2. Constant — ignore the argument, always return the same value
const constant = <T,>(x: T) => (): T => () => x;

// 3. Pipe a value through a series of transforms
function pipe<T>(value: T, ...fns: Array<(v: unknown) => unknown>): unknown {
  return fns.reduce((acc, fn) => fn(acc), value);
}

// 4. Type-safe Object.entries
function entries<T extends object>(obj: T): [keyof T, T[keyof T]][] {
  return Object.entries(obj) as [keyof T, T[keyof T]][];
}

// 5. Deeply partial — all nested properties become optional
type DeepPartial<T> = T extends object
  ? { [K in keyof T]?: DeepPartial<T[K]> }
  : T;

// 6. Non-nullable — strip null and undefined from T
type NonNullable<T> = T extends null | undefined ? never : T;

// 7. Flatten an array one level
function flatten<T>(arr: T[][]): T[] { return arr.flat(); }

// 8. Group-by — map T[] → Record<K, T[]>
function groupBy<T, K extends string>(
  items: T[],
  keyFn: (item: T) => K,
): Record<K, T[]> {
  return items.reduce((acc, item) => {
    const key = keyFn(item);
    (acc[key] = acc[key] ?? []).push(item);
    return acc;
  }, {} as Record<K, T[]>);
}

// Usage
interface Order { id: number; status: 'pending' | 'shipped' | 'delivered' }
const orders: Order[] = [
  { id: 1, status: 'pending' },
  { id: 2, status: 'shipped' },
  { id: 3, status: 'pending' },
];

const grouped = groupBy(orders, o => o.status);
// { pending: [o1, o3], shipped: [o2], delivered: [] }
